const RULES={
  topdown:['Assess weekly, daily, and 4H every Sunday — set bias before the week opens','Check Forex Factory every Sunday scan and every session for red folder events','2 out of 3 timeframes must agree on direction — 3/3 = A-grade priority pair','1/3 or split = skip entirely — do not trade','Do not change weekly bias mid-week unless a major structural break occurs','AOIs drawn from weekly and daily structure only — 4H confirms trend and times entry','When weekly AOI and daily AOI overlap at same price, combine into one tight zone — highest-probability entry'],
  entry:['Confirm 4H bias via market structure: HH/HL for buys, LL/LH for sells','Wait for a structural level to be broken and retested — no break, no trade','AOI validation: minimum 3 touches/reactions — fewer than 3 = no AOI, move on','Broken AOI rule: full candle body close through zone = zone is dead, drop to next level','Entry signal: engulfing candle swallowing 5+ prior candles at AOI retest','Momentum-loss confirmation: a large rejection wick at AOI (a loss-of-momentum signal — applies symmetrically to both bullish and bearish setups) = pre-signal — momentum-loss + engulf = highest quality entry','Wait for candle to fully close — forming candle is not a signal','Never enter against confirmed top-down bias — no counter-trend trades','Check Forex Factory for red folder news in next 60 mins before every entry'],
  risk:['1% risk per trade — no exceptions','Take profit at nearest structure point where price visibly reacted','Minimum 1:2 R:R must be mappable before entering — if not, skip the trade','Stop loss below AOI (buys) or above AOI (sells) — 5–10 pips beyond zone edge','Pre-accept full risk amount before entry — it is the cost of the trade','Do not close early to lock in profit before hitting planned target','Do not move stop to break even unless trade is significantly in profit'],
  session:['London session is primary — highest priority window','NY overlap with London is highest priority for all pairs','If signal fires outside session hours, wait — do not enter','Monday to Wednesday entries preferred — Thursday/Friday skip unless short target','No trading within 30 mins of red folder news — check Forex Factory before every entry','No trading on Friday close'],
};
